import React from "react"
import { properties } from '../../properties/properties.js'


class CyberAdmin extends React.Component {

    constructor(props) {
        super(props);
        this.state = { screen: 1, result: []
        };
    }




    createNewAlgorithm = (evt) => {


        this.setState({screen: 2})

    }


    componentDidMount() {

        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/algorithms`

        fetch(backUrl, {
          "method": "GET",
          headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({result: response})
            this.setState({screen: 1})
        })
        .catch(err => {
          console.log(err);
        });

    }


    render() {


        var header = "Loading ..."
        var content = []


        if (this.state.screen == 2) {
            header = ""

            var options = []
            options.push(<option key="1stHO" value="1stHO">1st HO</option>)
            options.push(<option key="2ndHO" value="2ndHO">2nd HO</option>)            
            options.push(<option key="3rdHO" value="3rdtHO">3rd HO</option>)
            options.push(<option key="4thHO" value="4thtHO">4th HO</option>)
            content.push(<div><select id="upTo">{options}</select> </div>)



        }


        if (this.state.screen == 1) {


            header = ""


            var tableContent = []
            tableContent.push(<tr><td style={{border:  borderStyleString, fontSize: '20px', padding: '5px'}}>Available algorithm</td></tr>)
            var borderStyleString = "1px solid black"

            for (var index in this.state.result) {

                var singleResult = this.state.result[index]
                var translateString = ""

                //********************************************************************** */
                var resFull = ""
                if (singleResult.resintern) {
                    resFull = " if resintern day"
                }
                if (singleResult.resintern != null && !singleResult.resintern) {
                    resFull = " (non-resintern)"
                }
                if (singleResult.fullteam) {
                    resFull = " if full team present"
                }

                var teamString = "each " + singleResult.type + " team" + resFull

                //********************************************************************** */
                var maxCensus = ""
                if (singleResult.max_census) {
                    maxCensus = ", up to census of " + singleResult.max_census
                }

                //********************************************************************** */
                var maxHO = ""
                if (singleResult.max_ho) {
                    maxHO = " (max* " + singleResult.max_ho + " HO)"
                }


                if (singleResult.current_ho || singleResult.current_ho == 0) {
                    var num 
                    if (singleResult.current_ho + 1 === 1) 
                        num = "st"
                    if (singleResult.current_ho + 1 === 2) 
                        num = "nd"
                    if (singleResult.current_ho + 1 == 3) 
                        num = "rd"
                    if (singleResult.current_ho + 1 > 3) 
                        num = "th"

                    translateString += (singleResult.current_ho + 1) + num + " HO to " + teamString

                    if (singleResult.census) {
                        if (singleResult.census < 0) {
                            translateString += " with starting census of " + singleResult.census * -1 + " or fewer"
                        } else {
                            translateString += " with starting census of " + singleResult.census
                        }
                    }

                    translateString += maxCensus + maxHO

                } else {
                    if (singleResult.ho)
                        translateString = "Up to " + singleResult.ho + " HO to " + teamString


                    translateString += maxCensus + maxHO


                }








                tableContent.push(<tr><td style={{border:  borderStyleString, padding: '10px'}}>{translateString}</td></tr>)
            }

            content.push(<div style={{marginBottom: "10px"}}><button style={{marginLeft: '12px'}} onClick={this.createNewAlgorithm} >Create New Algorithm</button></div>)

            content.push(<table style={{border: borderStyleString}}>{tableContent}</table>)



        }


        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }


}


export default CyberAdmin
